script.text:

function load$Posting$(g) {
	g._arrValue = [];
  g._$i = g._getColumnOrder('stt_rec');
  g._$t = g._getColumnOrder('&Tag;');
	g._$v = g._getColumnOrder('so_ct');
	g._$d = g._getColumnOrder('ngay_ct');
	g._$dt = g._getColumnOrder('chuoi_ngay');
	g.add_onResponseComplete(on$Posting$ResponseComplete);
  g.add_commandEvent(on$Posting$ExecuteCommand);
}
/* <flatten type="Javascript"> */
function dispose$Posting$(g) {
  g._$i = g._$t = null;
  try {g.remove_commandEvent(on$Posting$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$Posting$ResponseComplete);} catch (ex) {}
}
function scatter$Posting$(g) {
  fill$Grid(g, true);
  if (g._rowCount > 0) {
    g._activeRow = g._rowCount;
    g._activeColumn = g._$t;
    g._activeCell = g._getItem(g._activeRow, g._activeColumn);
	}
}
function on$Posting$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'GLPost':
			request$Posting(g, action);
      break;
    default:
      break;
  }
}

function request$Posting(g, c) {
  var count = 250;
  if (g._rowCount == 0) return;
	var arr = ['', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', ''], maxlength = g._arrValue.length;
	arr[0] = get$Value(g._arrValue, maxlength, 0, count, 0);
	arr[10] = get$Value(g._arrValue, maxlength, 0, count, 3);

	for (var r = 1; r < 10; r ++) {
    if (arr[r - 1] != '') {
      arr[r] = get$Value(g._arrValue, maxlength, r * count, r * count + count, 0);
			arr[r + 10] = get$Value(g._arrValue, maxlength, r * count, r * count + count, 3);
		}
	}

	var r = (g._activeCell ? g._activeRow : 1), o = g._getItemValue(r, g._$t);
	o.row = r;
	if (isCheck$Grid(g)) {
    var q = [];
    for (r = 0; r < 20; r ++) {
      var k = (r < 10 ? 'n' : 'd') + ((r == 0 || r == 10) ? '' : ((r % 10) + 1).toString());
      Array.add(q, [k, 'String', arr[r]]);
    }
    g.request(o, c, c, q);
  }
}
function on$Posting$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'GLPost':
			if(result[0].Value != '') {
				var msg = '', ar = ['', ''];
				find$Item(g._arrValue, ar, result[0].Value);
				if(result[1].Value == 1) msg = (g._language == 'v' ? 'Số chứng từ <span class="Highlight">' + ar[0] + ' </span>, ngày <span class="Highlight"> ' + ar[1] + '</span> đã khóa số liệu, kiểm tra lại ngày giới hạn hoặc ngày khóa sổ.' : 'Voucher numbered <span class="Highlight">' + ar[0] + ' </span>, dated <span class="Highlight">' + ar[1] + ' </span> data is locked, check locked date again.');
				  else msg = (g._language == 'v' ? 'Số chứng từ <span class="Highlight">' + ar[0] + ' </span>, ngày <span class="Highlight"> ' + ar[1] + '</span> đã được sửa hoặc xóa bởi người sử dụng khác.' : 'Voucher numbered <span class="Highlight">' + ar[0] + ' </span>, dated <span class="Highlight">' + ar[1] + ' </span> has been modified or deleted by another user.');
				$message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
				ar = [];
			}
      else {
				if (g._arrValue.length > 0) {
					g._arrValue = [];
          g.set_gridPageIndex(-2);
          g._loadPage(1);
				}
			}
			break;
    default:
      break;
  }
}
function addArray(o) {
	var a = o.id.split('_inputCell_'), g = $find(o.id.split('_inputCell_')[0]);
	if (!g) g = $find(a[0]);
	var r = $func.getLocationCell(o)[0];
	var v = g._getItemValue(r, g._$i), add = false;
  var item = [v, g._getItemValue(r, g._$v), g._getItem(r, g._$d).value, g._getItemValue(r, g._$dt)];
	for (var i = 0; i < g._arrValue.length; i ++) {
    if (g._arrValue[i][0] == v) {
			if(g._getItemValue(r, g._$t) == true)
				g._arrValue[i] = item;
			else
				g._arrValue.splice(i, 1);
      add = true;
			return;
		}
	}
  if (!add) Array.add(g._arrValue, item);
}
function get$Value(arr, maxLength, start, end, col) {
  if (maxLength < start) return '';
	var v = '';
	if (maxLength > end) {
    for (var row = start; row < end; row ++) {
		  v += (v == '' ? arr[row][col]: ',' + arr[row][col]);
		}
  }
	else {
    for (var row = start; row < maxLength; row ++) {
			  v += (v == '' ? arr[row][col]: ',' + arr[row][col]);
    }
  }
	return v;
}

function find$Item(arr, a, v) {
  for (var r = 0; r < arr.length; r ++) {
		if (arr[r][0] == v) {
			if (a == null) return r;
			a [0] = arr[r][1];
			a [1] = arr[r][2];
			return;
		}
	}
	return -1;
}

function fill$Grid(g) {
  if(g._gridRefresh) {
		g._arrValue = [];
		g._gridRefresh = false;
		return;
	}
	if (g._arrValue.length == 0) return;
	for (var r = 1; r <= g._rowCount; r++) {
    for (var row = 0; row < g._arrValue.length; row ++) {
			if (g._arrValue[row][0] == g._getItemValue(r, g._$i)) {
				 g._setItemValue(r, g._$t, 1);
			}
		}
	}
}

function toggle$Grid(o) {
  var c = o.parentNode.parentNode.parentNode.id, g = $find($func.left(c, c.length - 11));
  for (var r = 1; r <= g._rowCount; r++) {
    if (!g._getItem(r, g._$t).disabled) {
      var k = row$Key(g, r), i = find$Item(g._arrValue, null, k);
			var item = [k, g._getItemValue(r, g._$v), g._getItem(r, g._$d).value, g._getItemValue(r, g._$dt)];
			if(i == -1) Array.add(g._arrValue, item);
			else g._arrValue.splice(i, 1);
		}
		g._setItemValue(r, g._$t, (g._getItemValue(r, g._$t) == false));
	}
	g._focusWhenTabChanged();
}

function row$Key(g, r) {return g._getItemValue(r, g._$i);}
function isCheck$Grid(g) {
  var msg = (g._language == 'v' ? 'Chưa có bản ghi nào được chọn, phải đánh dấu trước khi thực hiện chức năng này.' : 'No record selected, please select at least one record to process.');
  if (g._arrValue.length == 0) {
    $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
    return false;
  }
  return true;
}
/* </flatten> */
      &JavascriptReportInit;
